def _format_long_image(self):
    """
    Break up long string value/comment into ``CONTINUE`` cards.
    This is a primitive implementation: it will put the value
    string in one block and the comment string in another.  Also,
    it does not break at the blank space between words.  So it may
    not look pretty.
    """
    if self.keyword in Card._commentary_keywords:
        return self._format_long_commentary_image()

    value_length = 67
    comment_length = 64
    output = []

    # do the value string
    value = self._value.replace("'", "''")
    words = _words_group(value, value_length)
    for idx, word in enumerate(words):
        if idx == 0:
            headstr = "{:{len}}= ".format(self.keyword, len=KEYWORD_LENGTH)
        else:
            headstr = "CONTINUE  "

        # If this is the final CONTINUE remove the '&'
        if not self.comment and idx == len(words) - 1:
            value_format = "'{}'"
        else:
            value_format = "'{}&'"

        value = value_format.format(word)

        output.append(f"{headstr + value:80}")

    # do the comment string
    comment_format = "{}"

    if self.comment:
        words = _words_group(self.comment, comment_length)
        for idx, word in enumerate(words):
            # If this is the final CONTINUE remove the '&'
            if idx == len(words) - 1:
                headstr = "CONTINUE  '' / "
            else:
                headstr = "CONTINUE  '&' / "

            comment = headstr + comment_format.format(word)
            output.append(f"{comment:80}")

    return "".join(output)

def _format_long_commentary_image(self):
    """
    If a commentary card's value is too long to fit on a single card, this
    will render the card as multiple consecutive commentary card of the
    same type.
    """

def _format_value(value):
    """
    Converts a card value to its appropriate string representation as
    defined by the FITS format.
    """
    # string value should occupies at least 8 columns, unless it is
    # a null string
    if isinstance(value, str):
        if value == "":
            return "''"
        else:
            exp_val_str = value.replace("'", "''")
            val_str = f"'{exp_val_str:8}'"
            return f"{val_str:20}"

    # must be before int checking since bool is also int
    elif isinstance(value, (bool, np.bool_)):
        return f"{repr(value)[0]:>20}"  # T or F

    elif _is_int(value):
        return f"{value:>20d}"

    elif isinstance(value, (float, np.floating)):
        return f"{_format_float(value):>20}"

    elif isinstance(value, (complex, np.complexfloating)):
        val_str = f"({_format_float(value.real)}, {_format_float(value.imag)})"
        return f"{val_str:>20}"

    elif isinstance(value, Undefined):
        return ""
    else:
        return ""


def _format_float(value):
    """Format a floating number to make sure it is at most 20 characters."""
    value_str = str(value).replace("e", "E")

    # Limit the value string to at most 20 characters.
    if (str_len := len(value_str)) > 20:
        idx = value_str.find("E")
        if idx < 0:
            # No scientific notation, truncate decimal places
            value_str = value_str[:20]
        else:
            # Scientific notation, truncate significand (mantissa)
            value_str = value_str[: 20 - (str_len - idx)] + value_str[idx:]

    return value_str


def _pad(input):
    """Pad blank space to the input string to be multiple of 80."""
    _len = len(input)
    if _len == Card.length:
        return input
    elif _len > Card.length:
        strlen = _len % Card.length
        if strlen == 0:
            return input
        else:
            return input + " " * (Card.length - strlen)

    # minimum length is 80
    else:
        strlen = _len % Card.length
        return input + " " * (Card.length - strlen)

def _parse_value(self):
    """Extract the keyword value from the card image."""
    # for commentary cards, no need to parse further
    # Likewise for invalid cards
    if self.keyword.upper() in self._commentary_keywords or self._invalid:
        return self._image[KEYWORD_LENGTH:].rstrip()

    if self._check_if_rvkc(self._image):
        return self._value

    m = self._value_NFSC_RE.match(self._split()[1])

    if m is None:
        raise VerifyError(
            f"Unparsable card ({self.keyword}), fix it first with .verify('fix')."
        )

    if m.group("bool") is not None:
        value = m.group("bool") == "T"
    elif m.group("strg") is not None:
        value = re.sub("''", "'", m.group("strg"))
    elif m.group("numr") is not None:
        #  Check for numbers with leading 0s.
        numr = self._number_NFSC_RE.match(m.group("numr"))
        digt = translate(numr.group("digt"), FIX_FP_TABLE2, " ")
        if numr.group("sign") is None:
            sign = ""
        else:
            sign = numr.group("sign")
        value = _str_to_num(sign + digt)

    elif m.group("cplx") is not None:
        #  Check for numbers with leading 0s.
        real = self._number_NFSC_RE.match(m.group("real"))
        rdigt = translate(real.group("digt"), FIX_FP_TABLE2, " ")
        if real.group("sign") is None:
            rsign = ""
        else:
            rsign = real.group("sign")
        value = _str_to_num(rsign + rdigt)
        imag = self._number_NFSC_RE.match(m.group("imag"))
        idigt = translate(imag.group("digt"), FIX_FP_TABLE2, " ")
        if imag.group("sign") is None:
            isign = ""
        else:
            isign = imag.group("sign")
        value += _str_to_num(isign + idigt) * 1j
    else:
        value = UNDEFINED

    if not self._valuestring:
        self._valuestring = m.group("valu")
    return value

